    biz_avg = rev_state.groupby(['state','key'])['rating'].mean().reset_index(name='biz_avg_rating')
    state_biz_avg = biz_avg[biz_avg['state']==max_state]['biz_avg_rating'].mean()

    out = {
        'state_with_highest_total_reviews': max_state,
